VALUES
  ('fire-eq-eng-moex-00263', 'fire-eq-eng', 'fire-eq-eng-moex-113-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依複合用途建築物判斷基準之規定，符合下列規定時，視為設置標準第12條第5款第2目之 複合用途建築物。複合用途建築物中，甲類場所樓地板面積合計小於該建築物總樓地板面 積X%。複合用途建築物中，甲類場所樓地板面積合計未滿Y平方公尺。X+Y是多少？', '["320", "310", "300", "290"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:14+00:00", "source_pdf_sha1": "50adaf9fdd02", "answer_pdf_sha1": "e7ca245227c2", "source_family": "moex-gov-tw", "moex": {"exam_code": "113050", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "113", "exam_name": "113年專技人員高等考試大地工程技師考試分階段考試(第一階段考試)、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00264', 'fire-eq-eng', 'fire-eq-eng-moex-113-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依各類場所消防安全設備設置標準第159條規定，各類場所之各樓層符合規定者，其應設之 避難器具得免設，下列敘述何者正確？', '["主要構造為防火構造，居室面向戶外部分，設有陽臺等有效避難設施，且該陽臺等設施設 有可通往地面之樓梯或通往他棟建築物之設施", "主要構造為防火構造，由居室或住戶可直接通往直通樓梯，且該居室或住戶所面向之直通 樓梯，設有隨時可自動關閉之具一小時以上防火時效之防火門（不含防火鐵捲門），且收容 人員未滿40人", "長期照顧服務機構各樓層以具半小時以上防火時效之牆壁及防火設備分隔為二個以上之區 劃，各區劃均以走廊連接安全梯，或分別連接不同安全梯", "兒童及少年福利機構設有自動撒水設備（含同等以上效能之滅火設備）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:14+00:00", "source_pdf_sha1": "50adaf9fdd02", "answer_pdf_sha1": "e7ca245227c2", "source_family": "moex-gov-tw", "moex": {"exam_code": "113050", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "113", "exam_name": "113年專技人員高等考試大地工程技師考試分階段考試(第一階段考試)、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00265', 'fire-eq-eng', 'fire-eq-eng-moex-113-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依各類場所消防安全設備設置標準有關泡沫滅火設備規定，下列敘述何者正確？', '["泡沫滅火設備之放射區域，使用泡沫噴頭時，每一放射區域在樓地板面積100平方公尺以 上200平方公尺以下", "泡沫滅火設備之放射區域，使用泡水噴頭時，放射區域占其樓地板面積三分之一以上，且 至少200平方公尺。但樓地板面積未達200平方公尺者，放射區域依其實際樓地板面積計算", "移動式泡沫滅火設備之水源容量，在二具泡沫瞄子同時放水20分鐘之水量以上", "泡沫原液與水混合使用之濃度，蛋白質泡沫液為5%或10%"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:14+00:00", "source_pdf_sha1": "50adaf9fdd02", "answer_pdf_sha1": "e7ca245227c2", "source_family": "moex-gov-tw", "moex": {"exam_code": "113050", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "113", "exam_name": "113年專技人員高等考試大地工程技師考試分階段考試(第一階段考試)、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00266', 'fire-eq-eng', 'fire-eq-eng-moex-113-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依各類場所消防安全設備設置標準規定，有關瓦斯漏氣火警自動警報設備之配線，除依用戶 用電設備裝置規則外，有關設置規定，下列敘述何者錯誤？', '["電源回路導線間及導線對大地間之絕緣電阻值，以直流600伏特額定之絕緣電阻計測定，對 地電壓在160伏特以下者，應在0.1 MΩ以上，對地電壓超過160伏特者，在0.2 MΩ以上", "檢知器回路導線間及導線與大地間之絕緣電阻值，以直流500伏特額定之絕緣電阻計測定， 每一警報分區在0.1 MΩ以上", "常開式檢知器信號回路之配線採用串接式，並加設終端電阻，以便藉由瓦斯漏氣受信總機 作斷線自動檢出用", "檢知器回路不得與瓦斯漏氣火警自動警報設備以外之設備回路共用"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:14+00:00", "source_pdf_sha1": "50adaf9fdd02", "answer_pdf_sha1": "e7ca245227c2", "source_family": "moex-gov-tw", "moex": {"exam_code": "113050", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "113", "exam_name": "113年專技人員高等考試大地工程技師考試分階段考試(第一階段考試)、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00267', 'fire-eq-eng', 'fire-eq-eng-moex-113-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依消防安全設備測試報告書測試方法及判定要領第2章室內消防栓設備規定，有關加壓送水 裝置消防幫浦試驗，關閉幫浦出水側之止水閥，測定全閉揚程、電壓及電流。其中全閉揚程 應在額定負荷運轉時之測得揚程的多少%以下？', '["110", "120", "130", "140"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:14+00:00", "source_pdf_sha1": "50adaf9fdd02", "answer_pdf_sha1": "e7ca245227c2", "source_family": "moex-gov-tw", "moex": {"exam_code": "113050", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "113", "exam_name": "113年專技人員高等考試大地工程技師考試分階段考試(第一階段考試)、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00268', 'fire-eq-eng', 'fire-eq-eng-moex-113-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依滅火器性能檢查及藥劑更換充填作業專業廠商認可及管理要點規定，為確保滅火器性能檢 查及藥劑更換充填作業品質，專業廠商應每A年會同當地消防機關，就滅火器性能檢查及藥 劑更換充填作業登記清冊抽樣B具，送內政部登錄機構就噴射時間、藥劑充填量、藥劑主成 分等項目進行檢測及保存。但滅火器抽樣檢測連續合格達C次者，得D年內免再辦理抽樣檢 測，有關A、B、C及D之敘述下列何者正確？', '["A＝3個月、B＝1具、C＝2次、D＝1年", "A＝半年、B＝1具、C＝2次、D＝2年", "A＝半年、B＝2具、C＝2次、D＝1年", "A＝1年、B＝2具、C＝3次、D＝2年"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:14+00:00", "source_pdf_sha1": "50adaf9fdd02", "answer_pdf_sha1": "e7ca245227c2", "source_family": "moex-gov-tw", "moex": {"exam_code": "113050", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "113", "exam_name": "113年專技人員高等考試大地工程技師考試分階段考試(第一階段考試)、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00269', 'fire-eq-eng', 'fire-eq-eng-moex-113-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據各類場所消防安全設備設置標準，緊急供電系統之配線除依用戶用電設備裝置規則外， 下列敘述何者錯誤？', '["緊急用電源回路及操作回路，使用300伏特耐熱絕緣電線，或同等耐熱效果以上之電線", "電源回路之配線，應施予耐燃保護，電線裝於金屬導線管槽內，並埋設於防火構造物之混 凝土內，混凝土保護厚度為20毫米以上", "使用MI電纜或耐燃電纜時，得按電纜裝設法，直接敷設", "電氣配線應設專用回路，不得與一般電路相接，且開關有消防安全設備別之明顯標示"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:14+00:00", "source_pdf_sha1": "50adaf9fdd02", "answer_pdf_sha1": "e7ca245227c2", "source_family": "moex-gov-tw", "moex": {"exam_code": "113050", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "113", "exam_name": "113年專技人員高等考試大地工程技師考試分階段考試(第一階段考試)、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00270', 'fire-eq-eng', 'fire-eq-eng-moex-113-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依消防機具器材及設備認可實施辦法規定，委託他人製造生產消防機具器材及設備者，有關 申請型式認可應依規定辦理事項，下列敘述何者錯誤？', '["檢附勞務委託契約證明文件，契約內容應載明產品於製造、加工、組裝及試驗時，契約雙 方之權利義務關係及其他必要事項", "試驗設備、試驗設備之維護管理及試驗場所概要說明書、品質管理說明書產品之設計圖等 文件，應有契約雙方負責人及公司之簽章", "使用受託者之試驗設備者，其試驗紀錄須有受託者操作人員及委託者會同人員之簽章", "產品有型式變更者，應由產製者提出申請"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:14+00:00", "source_pdf_sha1": "50adaf9fdd02", "answer_pdf_sha1": "e7ca245227c2", "source_family": "moex-gov-tw", "moex": {"exam_code": "113050", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "113", "exam_name": "113年專技人員高等考試大地工程技師考試分階段考試(第一階段考試)、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00271', 'fire-eq-eng', 'fire-eq-eng-moex-113-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依潔淨區消防安全設備設置要點規定，潔淨區應依各類場所消防安全設備設置標準第 28 條 規定，檢討設置或免設排煙設備。下列何者非屬上述免設排煙設備之條件？', '["為防火構造建築物", "避難步行距離符合建築技術規則建築設計施工編第93條之規定", "設有吸氣式偵煙探測系統", "設置室內消防栓設備"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:14+00:00", "source_pdf_sha1": "50adaf9fdd02", "answer_pdf_sha1": "e7ca245227c2", "source_family": "moex-gov-tw", "moex": {"exam_code": "113050", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "113", "exam_name": "113年專技人員高等考試大地工程技師考試分階段考試(第一階段考試)、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00272', 'fire-eq-eng', 'fire-eq-eng-moex-113-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依住宅用火災警報器設置辦法規定，有關住宅用火災警報器之裝置，下列敘述何者錯誤？', '["警報器下端距離天花板或樓板60公分以內", "裝設於距離牆面或樑60公分以上之位置", "裝置於牆面者，距天花板或樓板下方15公分以上45公分以下", "距離出風口1.5公尺以上"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:14+00:00", "source_pdf_sha1": "50adaf9fdd02", "answer_pdf_sha1": "e7ca245227c2", "source_family": "moex-gov-tw", "moex": {"exam_code": "113050", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "113", "exam_name": "113年專技人員高等考試大地工程技師考試分階段考試(第一階段考試)、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL)
